from collections import Counter

class LoopDetector:
    def __init__(self):
        self.tool_calls = Counter()
        self.max_calls = 3

    def check_loop(self, event):
        if 'tool' in event:
            tool_name = event['tool']
            self.tool_calls[tool_name] += 1
            if self.tool_calls[tool_name] > self.max_calls:
                return {'loop_detected': True, 'tool': tool_name}
        return {'loop_detected': False}

import hashlib
from llama_index.core.query_engine import BaseQueryEngine

class QueryLoopDetector:
    def __init__(self):
        self.query_hashes = set()
        self.call_count = 0

    def wrap_query(self, query_engine: BaseQueryEngine):
        def wrapped_query(query_str):
            self.call_count += 1
            query_hash = hashlib.md5(query_str.encode()).hexdigest()
            if query_hash in self.query_hashes:
                raise Exception(f'LOOP DETECTED: Query repeated {self.call_count} times')
            self.query_hashes.add(query_hash)
            return query_engine.query(query_str)
        return wrapped_query

from typing import List, Dict

class StateCycleDetector:
    def __init__(self, max_states: int = 5):
        self.state_history: List[Dict] = []
        self.max_states = max_states

    def record_state(self, state: Dict):
        self.state_history.append(state)
        if len(self.state_history) > self.max_states:
            self.state_history.pop(0)

        # Check for cycle
        recent_states = self.state_history[-3:]
        if len(set(tuple(d.items()) for d in recent_states)) < len(recent_states):
            return {'cycle_detected': True, 'states': recent_states}
        return {'cycle_detected': False}

